SELECT certificate_id, member_name, cert_type, issue_date, status, req_date FROM erp_certificate
AND (member_name LIKE '%' || #{keyword} || '%' OR cert_type LIKE '%' || #{keyword} || '%')
ORDER BY req_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT approval_id, title, requester_name, submit_date, approver_name, approve_date, status FROM erp_approval
AND (title LIKE '%' || #{keyword} || '%' OR requester_name LIKE '%' || #{keyword} || '%')
ORDER BY submit_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT minutes_id, title, meeting_date, participants, content, author_name, reg_date FROM erp_minutes
AND (title LIKE '%' || #{keyword} || '%' OR author_name LIKE '%' || #{keyword} || '%')
ORDER BY meeting_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT archive_id, title, doc_type, file_path, reg_by, status, reg_date FROM erp_archive
AND (title LIKE '%' || #{keyword} || '%' OR doc_type LIKE '%' || #{keyword} || '%')
ORDER BY reg_date DESC LIMIT #{limit} OFFSET #{offset}
